119	                    else
120	                        WrAddr <= std_logic_vector(unsigned(WrAddr) + 1);
121	                    end if;
122	                    -- read address
123	                    if unsigned(RdAddr) = MemTaps_c - 1 then
124	                        RdAddr <= (others => '0');
125	                    else
126	                        RdAddr <= std_logic_vector(unsigned(RdAddr) + 1);
127	                    end if;
128	                end if;
129	
130	                -- Reset
