1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2025 by Oliver Bruendler
3	-- Author: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Description
8	---------------------------------------------------------------------------------------------------
9	-- This component limits the rate of AXI4-Stream style handshaked interfaces to a specified
10	-- maximum data rate. It can be used to avoid overloading downstream components. This is especially
11	-- useful when interfacing to components that have limited processing capabilities and do not
12	-- support back-pressure (i.e. do not de-assert Ready signals).
13	--
14	-- The component has two modes of operation:
15	-- - BLOCK: Forward short bursts at full speed but limit average rate over fixed periods
16	-- - SMOOTH: Space samples evenly over time to achieve constant output data rate
17	--
18	-- Documentation:
19	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_rate_limit.md
20	--
21	-- Note: The link points to the documentation of the latest release. If you
22	--       use an older version, the documentation might not match the code.
23	
24	---------------------------------------------------------------------------------------------------
25	-- Libraries
26	---------------------------------------------------------------------------------------------------
27	library ieee;
28	    use ieee.std_logic_1164.all;
29	    use ieee.numeric_std.all;
30	
31	library work;
32	    use work.olo_base_pkg_math.all;
33	    use work.olo_base_pkg_string.all;
34	    use work.olo_base_pkg_logic.all;
35	
36	---------------------------------------------------------------------------------------------------
37	-- Entity
38	---------------------------------------------------------------------------------------------------
39	entity olo_base_rate_limit is
40	    generic (
41	        Width_g         : positive;
42	        RegisterReady_g : boolean  := true;
43	        Mode_g          : string   := "SMOOTH";
44	        Period_g        : positive;
45	        MaxSamples_g    : positive := 1;
46	        RuntimeCfg_g    : boolean  := false
47	    );
48	    port (
49	        -- Control
50	        Clk             : in    std_logic;
51	        Rst             : in    std_logic;
52	        -- Input Data
53	        In_Data         : in    std_logic_vector(Width_g-1 downto 0);
54	        In_Valid        : in    std_logic                                           := '1';
55	        In_Ready        : out   std_logic;
56	        -- Output Data
57	        Out_Data        : out   std_logic_vector(Width_g-1 downto 0);
58	        Out_Valid       : out   std_logic;
59	        Out_Ready       : in    std_logic                                           := '1';
60	        -- Configuration Ports (for RuntimeCfg_g = true)
61	        Cfg_Period      : in    std_logic_vector(log2ceil(Period_g)-1 downto 0)     := toUslv(Period_g-1, log2ceil(Period_g));
62	        Cfg_MaxSamples  : in    std_logic_vector(log2ceil(MaxSamples_g)-1 downto 0) := toUslv(MaxSamples_g-1, log2ceil(MaxSamples_g))
63	    );
64	end entity;
65	
66	---------------------------------------------------------------------------------------------------
67	-- Architecture
68	---------------------------------------------------------------------------------------------------
69	architecture rtl of olo_base_rate_limit is
70	
71	    -- Constants
72	    constant EntityName_c : string := "olo_base_rate_limit";
73	
74	    -- Signals
75	    signal Input_Ready : std_logic;
76	    signal Input_Valid : std_logic;
77	    signal Input_Data  : std_logic_vector(Width_g-1 downto 0);
78	
79	begin
80	
81	    -- *** Assertions ***
82	    assert MaxSamples_g <= Period_g
83	        report errorMessage(EntityName_c, "MaxSamples_g (" & integer'image(MaxSamples_g) &
84	               ") must be <= Period_g (" & integer'image(Period_g) & ")")
85	        severity failure;
86	
87	    assert compareNoCase(Mode_g, "SMOOTH") or compareNoCase(Mode_g, "BLOCK")
88	        report errorMessage(EntityName_c, "Mode_g must be either ""SMOOTH"" or ""BLOCK"", got """ & Mode_g & """")
89	        severity failure;
90	
91	    -- *** Add Input Register if Required ***
92	    -- Ready registered
93	    g_ready_registered : if RegisterReady_g generate
94	
95	        i_pl_stage : entity work.olo_base_pl_stage
96	            generic map (
97	                Width_g => Width_g
98	            )
99	            port map (
100	                Clk       => Clk,
101	                Rst       => Rst,
102	                In_Data   => In_Data,
103	                In_Valid  => In_Valid,
104	                In_Ready  => In_Ready,
105	                Out_Data  => Input_Data,
106	                Out_Valid => Input_Valid,
107	                Out_Ready => Input_Ready
108	            );
109	
110	    end generate;
111	
112	    -- Ready unregistered
113	    g_ready_unregistered : if not RegisterReady_g generate
114	        Input_Valid <= In_Valid;
115	        In_Ready    <= Input_Ready;
116	        Input_Data  <= In_Data;
117	    end generate;
118	
119	    -- *** Generate statement for NO RATE LIMIT ***
120	    -- Period_g = 1 means that there is no rate limit because every clock cycle a
121	    -- sample can be transferred.
122	    g_no_rate_limit : if Period_g = 1 generate
123	        -- Direct wire-through without any rate limiting
124	        Out_Valid   <= Input_Valid;
125	        Input_Ready <= Out_Ready;
126	        Out_Data    <= Input_Data;
127	    end generate;
128	
129	    -- *** Generate statement for ACTIVE RATE LIMIT when Period_g > 1 ***
130	    g_rate_limit : if Period_g > 1 generate
131	        -- Two process method signals
132	        type TwoProcess_r is record
133	            -- SMOOTH mode signals
134	            SmoothCounter  : unsigned(log2ceil(Period_g+MaxSamples_g)-1 downto 0);
135	            -- BLOCK mode signals
136	            PeriodCounter  : integer range 0 to Period_g-1;
137	            SamplesCounter : integer range 0 to MaxSamples_g+1;
138	            -- Runtime configuration signals
139	            CfgPeriod      : std_logic_vector(Cfg_Period'range);
140	            CfgMaxSamples  : std_logic_vector(Cfg_MaxSamples'range);
141	            CfgSmoothLimit : unsigned(Cfg_Period'range);
142	        end record;
143	
144	        signal r, r_next : TwoProcess_r;
145	
146	        -- Internal signals to avoid reading back output ports
147	        signal Out_Valid_i : std_logic;
148	        signal In_Ready_i  : std_logic;
149	        signal AllowSample : std_logic;
150	
151	    begin
152	
153	        -- Combinatorial process
154	        p_comb : process (all) is
155	            variable v                : TwoProcess_r;
156	            variable OutputTransfer_v : boolean;
157	            variable PeriodMin1_v     : natural; -- Period minus 1
158	            variable MaxSamples_v     : natural;
159	            variable SmoothLimit_v    : natural;
160	        begin
161	            -- Hold variables stable
162	            v := r;
163	
164	            -- Register Runtime Configuration signals
165	            if RuntimeCfg_g then
166	                v.CfgPeriod     := to01(Cfg_Period);
167	                v.CfgMaxSamples := to01(Cfg_MaxSamples);
168	                -- to01 and resize required to workaround simulation issues. Functionally they do not
169	                -- have impact so this is tolerable.
170	                v.CfgSmoothLimit := unsigned(to01(Cfg_Period)) - resize(unsigned(to01(Cfg_MaxSamples)), Cfg_Period'length);
171	                PeriodMin1_v     := to_integer(unsigned(to01(r.CfgPeriod))); -- This is period minus 1 because the definition of the port is like that
172	                MaxSamples_v     := to_integer(unsigned(to01(r.CfgMaxSamples)))+1;
173	                SmoothLimit_v    := to_integer(r.CfgSmoothLimit);
174	                -- synthesis translate_off
175	                assert MaxSamples_v <= PeriodMin1_v+1
176	                    report errorMessage(EntityName_c, "Runtime configured requires Cfg_MaxSamples <= Cfg_Period")
177	                    severity failure;
178	                -- synthesis translate_on
179	            else
180	                PeriodMin1_v  := Period_g - 1;
181	                MaxSamples_v  := MaxSamples_g;
182	                SmoothLimit_v := Period_g - MaxSamples_g; -- off by one correction
183	            end if;
184	
185	            -- Detect successful output transfer (rate limiter output to downstream)
186	            OutputTransfer_v := (Out_Valid_i = '1' and Out_Ready = '1');
187	
188	            -- SMOOTH Mode Logic
189	            if compareNoCase(Mode_g, "SMOOTH") then
190	
191	                -- Update counter: either decrement (on transfer) OR increment (building credit)
192	                if OutputTransfer_v then
193	                    v.SmoothCounter := r.SmoothCounter - SmoothLimit_v;
194	                elsif r.SmoothCounter < SmoothLimit_v then
195	                    v.SmoothCounter := r.SmoothCounter + MaxSamples_v;
196	                end if;
197	
198	                -- Allow sample logic
199	                if r.SmoothCounter >= SmoothLimit_v then
200	                    AllowSample <= '1';
201	                else
202	                    AllowSample <= '0';
203	                end if;
204	
205	            -- BLOCK Mode Logic
206	            else -- Mode_g = "BLOCK"
207	
208	                -- Samples counting (increment only when actually outputting)
209	                if OutputTransfer_v then
210	                    v.SamplesCounter := r.SamplesCounter + 1;
211	                end if;
212	
213	                -- Period Handling
214	                if r.PeriodCounter >= PeriodMin1_v then
215	                    v.PeriodCounter  := 0;
216	                    v.SamplesCounter := 0;
217	                else
218	                    v.PeriodCounter := r.PeriodCounter + 1;
219	                end if;
220	
221	                -- Allow sample logic
222	                if r.SamplesCounter < MaxSamples_v then
223	                    AllowSample <= '1';
224	                else
225	                    AllowSample <= '0';
226	                end if;
227	            end if;
228	
229	            -- Assign to next state
230	            r_next <= v;
231	        end process;
232	
233	        -- Sequential process
234	        p_seq : process (Clk) is
235	        begin
236	            if rising_edge(Clk) then
237	                r <= r_next;
238	                if Rst = '1' then
239	                    r.SmoothCounter  <= (others => '0');
240	                    r.PeriodCounter  <= 0;
241	                    r.SamplesCounter <= 0;
242	                    r.CfgPeriod      <= toUslv(Period_g-1, Cfg_Period'length);
243	                    r.CfgMaxSamples  <= toUslv(MaxSamples_g-1, Cfg_MaxSamples'length);
244	                    r.CfgSmoothLimit <= to_unsigned(Period_g - MaxSamples_g + 1, Cfg_Period'length);
245	                end if;
246	            end if;
247	        end process;
248	
249	        -- Gated handshaking signals
250	        Out_Valid_i <= Input_Valid and AllowSample;
251	        In_Ready_i  <= Out_Ready and AllowSample;
252	
253	        -- Output Port Assignment
254	        Out_Valid   <= Out_Valid_i;
